     1→import "dotenv/config";
     2→import express from "express";
     3→import cors from "cors";
     4→import compression from "compression";
     5→import helmet from "helmet";
     6→import morgan from "morgan";
     7→import path from "path";
     8→import fs from "fs";
     9→import { fileURLToPath } from "url";
    10→import { db, adminSettingsTable } from "./db.js";
    11→import authRouter  from "./routes/auth.js";
    12→import adminRouter from "./routes/admin.js";
    13→
    14→const __dirname = path.dirname(fileURLToPath(import.meta.url));
    15→const PORT   = parseInt(process.env.PORT || "3000", 10);
    16→const isProd = process.env.NODE_ENV === "production";
    17→
    18→// dist is always next to package.json, not next to server/
    19→const distDir     = path.resolve(__dirname, "../dist");
    20→const indexHtml   = path.join(distDir, "index.html");
    21→
    22→const app = express();
    23→
    24→// ─── Security ────────────────────────────────────────────────────────────────
    25→app.use(helmet({
    26→  contentSecurityPolicy: {
    27→    directives: {
    28→      defaultSrc:  ["'self'"],
    29→      scriptSrc:   ["'self'", "'unsafe-inline'", "'unsafe-eval'"],
    30→      styleSrc:    ["'self'", "'unsafe-inline'", "https://fonts.googleapis.com"],
    31→      fontSrc:     ["'self'", "https://fonts.gstatic.com"],
    32→      imgSrc:      ["'self'", "data:", "blob:", "https:"],
    33→      connectSrc:  ["'self'"],
    34→      workerSrc:   ["'self'", "blob:"],
    35→      objectSrc:   ["'none'"],
    36→      upgradeInsecureRequests: [],
    37→    },
    38→  },
    39→  crossOriginEmbedderPolicy: false,
    40→}));
    41→app.use(compression());
    42→app.use(cors({ origin: "*" }));
    43→app.use(express.json({ limit: "2mb" }));
    44→app.use(express.urlencoded({ extended: true }));
    45→app.use(morgan(isProd ? "combined" : "dev"));
    46→
    47→// ─── API Routes ──────────────────────────────────────────────────────────────
    48→app.use("/api/auth",  authRouter);
    49→app.use("/api/admin", adminRouter);
    50→
    51→app.get("/api/healthz", (_req, res) => res.json({ status: "ok", timestamp: new Date().toISOString() }));
    52→
    53→// Public settings (no auth required)
    54→app.get("/api/settings", async (_req, res) => {
    55→  try {
    56→    const rows = await db.select().from(adminSettingsTable);
    57→    const settings = {};
    58→    rows.forEach(r => { settings[r.key] = r.value; });
    59→    return res.json({ settings });
    60→  } catch {
    61→    return res.json({ settings: {} });
    62→  }
    63→});
    64→
    65→// ─── Static frontend ─────────────────────────────────────────────────────────
    66→if (fs.existsSync(distDir)) {
    67→  app.use(express.static(distDir, {
    68→    maxAge: isProd ? "7d" : 0,
    69→    etag: true,
    70→    index: false, // disable auto-index so we control it
    71→    setHeaders(res, filePath) {
    72→      if (filePath.endsWith(".html")) {
    73→        res.setHeader("Cache-Control", "no-cache, no-store, must-revalidate");
    74→      }
    75→    },
    76→  }));
    77→
    78→  // SPA fallback — all non-API routes serve index.html for React Router
    79→  app.get("*", (req, res) => {
    80→    if (req.path.startsWith("/api/")) {
    81→      return res.status(404).json({ error: "API route not found." });
    82→    }
    83→    if (!fs.existsSync(indexHtml)) {
    84→      return res.status(503).send("Frontend not built. Run: npm run build");
    85→    }
    86→    res.sendFile(indexHtml);
    87→  });
    88→} else {
    89→  app.get("*", (_req, res) => {
    90→    res.status(503).send(`
    91→      <h2>Frontend not built</h2>
    92→      <p>Run <code>npm run build</code> then restart the server.</p>
    93→    `);
    94→  });
    95→}
    96→
    97→// ─── 500 handler ─────────────────────────────────────────────────────────────
    98→app.use((err, _req, res, _next) => {
    99→  console.error("[error]", err?.message || err);
   100→  res.status(500).json({ error: "Internal server error." });
   101→});
   102→
   103→// ─── Start ───────────────────────────────────────────────────────────────────
   104→const server = app.listen(PORT, "0.0.0.0", () => {
   105→  console.log("");
   106→  console.log(`  🚀 BruteScale is running`);
   107→  console.log(`  ➜  http://localhost:${PORT}`);
   108→  console.log(`  ➜  API: http://localhost:${PORT}/api/healthz`);
   109→  if (!fs.existsSync(distDir)) {
   110→    console.log("");
   111→    console.log("  ⚠️  No /dist folder found. Run: npm run build");
   112→  }
   113→  console.log("");
   114→});
   115→
   116→function shutdown(signal) {
   117→  console.log(`\n${signal} — shutting down gracefully...`);
   118→  server.close(() => { console.log("Server closed."); process.exit(0); });
   119→  setTimeout(() => process.exit(1), 10_000);
   120→}
   121→process.on("SIGTERM", () => shutdown("SIGTERM"));
   122→process.on("SIGINT",  () => shutdown("SIGINT"));
