    13→  const handleMouseMove = (e: any) => {
    14→    const rect = e.currentTarget.getBoundingClientRect();
    15→    const centerX = rect.left + rect.width / 2;
    16→    const centerY = rect.top + rect.height / 2;
    17→    x.set((e.clientX - centerX) * 0.3);
    18→    y.set((e.clientY - centerY) * 0.3);
    19→  };
    20→  
    21→  const handleMouseLeave = () => { 
    22→    x.set(0); 
    23→    y.set(0); 
    24→  };
    25→  
    26→  return (
    27→    <motion.button
    28→      style={{ x: springX, y: springY }}
    29→      onMouseMove={handleMouseMove}
    30→      onMouseLeave={handleMouseLeave}
    31→      className={primary ? "btn-primary-glow" : "btn-ghost-glow"}
    32→      onClick={onClick}
    33→      {...props}
    34→    >
    35→      {children}
