import { useState, useEffect, useCallback } from "react";
import { AnimatePresence, motion } from "framer-motion";
import { Plus, Pencil, Trash2, Eye, EyeOff, RefreshCw, Youtube, Instagram, MessageSquare, Star } from "lucide-react";
import { Toast, ConfirmDialog, GlassInput, GlassTextarea, GlassSelect, Card, SectionHeader, SaveButton, Modal } from "./shared";

interface Review {
  id: number; type: string; visible: number; sortOrder: number;
  thumbnailUrl: string | null; title: string | null; creator: string | null;
  uploadDate: string | null; videoUrl: string | null; caption: string | null;
  reelUrl: string | null; screenshotUrl: string | null; reviewer: string | null;
  message: string | null; rating: number | null; createdAt: string;
}

const TABS = [
  { id: "youtube",   label: "YouTube",   icon: Youtube,       color: "#ff0000" },
  { id: "instagram", label: "Instagram", icon: Instagram,     color: "#e1306c" },
  { id: "discord",   label: "Discord",   icon: MessageSquare, color: "#5865f2" },
];

function extractYTId(url: string): string {
  const m = url.match(/(?:v=|youtu\.be\/|embed\/)([A-Za-z0-9_-]{11})/);
  return m ? m[1] : "";
}

function ytThumb(id: string) {
  return id ? `https://img.youtube.com/vi/${id}/mqdefault.jpg` : "";
}

const EMPTY_FORM = {
  videoUrl: "", title: "", creator: "", uploadDate: "",
  thumbnailUrl: "", caption: "", reelUrl: "", screenshotUrl: "",
  reviewer: "", message: "", rating: "5", sortOrder: "0", visible: true,
};

export default function ReviewsManager({ token }: { token: string }) {
  const [tab, setTab] = useState("youtube");
  const [reviews, setReviews] = useState<Review[]>([]);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [modal, setModal] = useState<null | "add" | number>(null);
  const [form, setForm] = useState({ ...EMPTY_FORM });
  const [confirmId, setConfirmId] = useState<number | null>(null);
  const [toast, setToast] = useState<{ msg: string; type: "success" | "error" } | null>(null);

  const load = useCallback(async () => {
    setLoading(true);
    try {
      const r = await fetch("/api/reviews/admin", { headers: { Authorization: `Bearer ${token}` } });
      const d = await r.json() as { reviews?: Review[] };
      setReviews(d.reviews ?? []);
    } finally { setLoading(false); }
  }, [token]);

  useEffect(() => { load(); }, [load]);

  const tabReviews = reviews.filter(r => r.type === tab);

  const openAdd = () => { setForm({ ...EMPTY_FORM }); setModal("add"); };
  const openEdit = (r: Review) => {
    setForm({
      videoUrl: r.videoUrl ?? "", title: r.title ?? "", creator: r.creator ?? "",
      uploadDate: r.uploadDate ?? "", thumbnailUrl: r.thumbnailUrl ?? "",
      caption: r.caption ?? "", reelUrl: r.reelUrl ?? "",
      screenshotUrl: r.screenshotUrl ?? "", reviewer: r.reviewer ?? "",
      message: r.message ?? "", rating: String(r.rating ?? 5),
      sortOrder: String(r.sortOrder), visible: r.visible === 1,
    });
    setModal(r.id);
  };

  const set = (k: string, v: string | boolean) => setForm(f => ({ ...f, [k]: v }));

  const handleVideoUrl = (url: string) => {
    set("videoUrl", url);
    const id = extractYTId(url);
    if (id && !form.thumbnailUrl) set("thumbnailUrl", ytThumb(id));
  };

  const buildPayload = () => {
    const base = {
      type: tab, visible: form.visible ? 1 : 0,
      sortOrder: Number(form.sortOrder) || 0,
      thumbnailUrl: form.thumbnailUrl || null,
      title: form.title || null, creator: form.creator || null,
      uploadDate: form.uploadDate || null, videoUrl: form.videoUrl || null,
      caption: form.caption || null, reelUrl: form.reelUrl || null,
      screenshotUrl: form.screenshotUrl || null,
      reviewer: form.reviewer || null, message: form.message || null,
      rating: Number(form.rating) || 5,
    };
    return base;
  };

  const save = async () => {
    setSaving(true);
    try {
      const isEdit = typeof modal === "number";
      const url = isEdit ? `/api/reviews/${modal}` : "/api/reviews";
      const method = isEdit ? "PATCH" : "POST";
      const r = await fetch(url, {
        method, headers: { Authorization: `Bearer ${token}`, "Content-Type": "application/json" },
        body: JSON.stringify(buildPayload()),
      });
      if (r.ok) {
        setToast({ msg: isEdit ? "Review updated." : "Review added.", type: "success" });
        setModal(null);
        load();
      } else {
        const e = await r.json() as { error?: string };
        setToast({ msg: e.error ?? "Failed to save.", type: "error" });
      }
    } finally { setSaving(false); }
  };

  const toggleVisible = async (rev: Review) => {
    await fetch(`/api/reviews/${rev.id}`, {
      method: "PATCH",
      headers: { Authorization: `Bearer ${token}`, "Content-Type": "application/json" },
      body: JSON.stringify({ visible: rev.visible === 1 ? 0 : 1 }),
    });
    setReviews(rs => rs.map(r => r.id === rev.id ? { ...r, visible: r.visible === 1 ? 0 : 1 } : r));
  };

  const deleteReview = async (id: number) => {
    const r = await fetch(`/api/reviews/${id}`, { method: "DELETE", headers: { Authorization: `Bearer ${token}` } });
    if (r.ok) { setToast({ msg: "Review deleted.", type: "success" }); setReviews(rs => rs.filter(r => r.id !== id)); }
    else setToast({ msg: "Delete failed.", type: "error" });
    setConfirmId(null);
  };

  const activeTab = TABS.find(t => t.id === tab)!;

  return (
    <div>
      <SectionHeader title="Reviews Manager" subtitle="Manage YouTube, Instagram, and Discord reviews" />
      {toast && <AnimatePresence><Toast msg={toast.msg} type={toast.type} onClose={() => setToast(null)} /></AnimatePresence>}
      {confirmId !== null && <ConfirmDialog msg="Permanently delete this review?" onConfirm={() => deleteReview(confirmId)} onCancel={() => setConfirmId(null)} />}

      {modal !== null && (
        <AnimatePresence>
          <Modal title={typeof modal === "number" ? "Edit Review" : `Add ${activeTab.label} Review`} onClose={() => setModal(null)}>
            <div className="space-y-4">
              {tab === "youtube" && (
                <>
                  <GlassInput label="YouTube Video URL" value={form.videoUrl} onChange={handleVideoUrl} placeholder="https://youtube.com/watch?v=..." />
                  {form.thumbnailUrl && <img src={form.thumbnailUrl} alt="thumb" className="w-full h-32 object-cover rounded-xl opacity-80" />}
                  <GlassInput label="Thumbnail URL (auto-filled)" value={form.thumbnailUrl} onChange={v => set("thumbnailUrl", v)} placeholder="https://img.youtube.com/..." />
                  <GlassInput label="Video Title" value={form.title} onChange={v => set("title", v)} placeholder="Amazing Minecraft Hosting Review" />
                  <GlassInput label="Creator Name" value={form.creator} onChange={v => set("creator", v)} placeholder="TechReviewer" />
                  <GlassInput label="Upload Date" value={form.uploadDate} onChange={v => set("uploadDate", v)} placeholder="Jan 15, 2025" />
                  <GlassTextarea label="Description" value={form.caption} onChange={v => set("caption", v)} rows={2} placeholder="Short description..." />
                </>
              )}
              {tab === "instagram" && (
                <>
                  <GlassInput label="Reel / Post URL" value={form.reelUrl} onChange={v => set("reelUrl", v)} placeholder="https://www.instagram.com/reel/..." />
                  <GlassInput label="Thumbnail URL" value={form.thumbnailUrl} onChange={v => set("thumbnailUrl", v)} placeholder="https://..." />
                  {form.thumbnailUrl && <img src={form.thumbnailUrl} alt="thumb" className="w-full h-32 object-cover rounded-xl opacity-80" />}
                  <GlassInput label="Creator / @username" value={form.creator} onChange={v => set("creator", v)} placeholder="@username" />
                  <GlassTextarea label="Caption" value={form.caption} onChange={v => set("caption", v)} rows={3} placeholder="Post caption..." />
                </>
              )}
              {tab === "discord" && (
                <>
                  <GlassInput label="Screenshot URL" value={form.screenshotUrl} onChange={v => set("screenshotUrl", v)} placeholder="https://... (upload in Media first)" />
                  {form.screenshotUrl && <img src={form.screenshotUrl} alt="screenshot" className="w-full h-32 object-cover rounded-xl opacity-80" />}
                  <GlassInput label="Reviewer Username" value={form.reviewer} onChange={v => set("reviewer", v)} placeholder="Username#0000" />
                  <GlassTextarea label="Review Message" value={form.message} onChange={v => set("message", v)} rows={3} placeholder="Great hosting service..." />
                  <GlassSelect label="Rating" value={form.rating} onChange={v => set("rating", v)}
                    options={[5,4,3,2,1].map(n => ({ value: String(n), label: "★".repeat(n) + " " + n + " / 5" }))} />
                </>
              )}
              <div className="grid grid-cols-2 gap-4">
                <GlassInput label="Sort Order" value={form.sortOrder} onChange={v => set("sortOrder", v)} type="number" placeholder="0" />
                <div>
                  <label className="block text-xs font-semibold text-white/40 uppercase tracking-widest mb-1.5">Visibility</label>
                  <button onClick={() => set("visible", !form.visible)}
                    className="w-full flex items-center gap-2 px-4 py-2.5 rounded-xl text-sm font-medium transition-all"
                    style={{ background: form.visible ? "rgba(16,185,129,0.12)" : "rgba(255,255,255,0.04)", border: `1px solid ${form.visible ? "rgba(16,185,129,0.3)" : "rgba(255,255,255,0.08)"}`, color: form.visible ? "#34d399" : "rgba(255,255,255,0.4)" }}>
                    {form.visible ? <Eye size={14} /> : <EyeOff size={14} />}
                    {form.visible ? "Visible" : "Hidden"}
                  </button>
                </div>
              </div>
              <div className="pt-2">
                <SaveButton loading={saving} onClick={save} label={typeof modal === "number" ? "Update Review" : "Add Review"} />
              </div>
            </div>
          </Modal>
        </AnimatePresence>
      )}

      {/* Tabs */}
      <div className="flex gap-2 mb-6">
        {TABS.map(t => {
          const Icon = t.icon;
          const active = tab === t.id;
          return (
            <button key={t.id} onClick={() => setTab(t.id)}
              className="flex items-center gap-2 px-4 py-2 rounded-xl text-sm font-medium transition-all"
              style={{
                background: active ? `${t.color}18` : "rgba(255,255,255,0.04)",
                border: `1px solid ${active ? t.color + "40" : "rgba(255,255,255,0.08)"}`,
                color: active ? t.color : "rgba(255,255,255,0.45)",
              }}>
              <Icon size={14} />
              {t.label}
              <span className="ml-1 text-xs opacity-60">{reviews.filter(r => r.type === t.id).length}</span>
            </button>
          );
        })}
        <button onClick={load} className="ml-auto flex items-center gap-1.5 px-3 py-2 rounded-xl text-xs text-white/40 hover:text-white border border-white/8 hover:border-white/20 transition-colors">
          <RefreshCw size={12} /> Refresh
        </button>
        <button onClick={openAdd}
          className="flex items-center gap-2 px-4 py-2 rounded-xl text-sm font-semibold text-white transition-all"
          style={{ background: "linear-gradient(135deg,#2563eb,#7c3aed)", boxShadow: "0 0 16px rgba(99,102,241,0.3)" }}>
          <Plus size={14} /> Add
        </button>
      </div>

      <Card>
        {loading ? (
          <div className="text-center py-12 text-white/30 text-sm">Loading reviews...</div>
        ) : tabReviews.length === 0 ? (
          <div className="text-center py-12 text-white/25 text-sm">No {activeTab.label} reviews yet. Click Add to create one.</div>
        ) : (
          <div className="space-y-3">
            {tabReviews.map(rev => (
              <motion.div key={rev.id} initial={{ opacity: 0 }} animate={{ opacity: 1 }}
                className="flex items-center gap-4 p-3 rounded-xl transition-colors hover:bg-white/3"
                style={{ border: "1px solid rgba(255,255,255,0.06)" }}>
                {(rev.thumbnailUrl || rev.screenshotUrl) && (
                  <img src={rev.thumbnailUrl ?? rev.screenshotUrl ?? ""} alt="" className="w-16 h-12 object-cover rounded-lg shrink-0 opacity-80" />
                )}
                <div className="flex-1 min-w-0">
                  <div className="text-white text-sm font-medium truncate">{rev.title ?? rev.reviewer ?? rev.creator ?? "Untitled"}</div>
                  <div className="text-white/35 text-xs truncate mt-0.5">
                    {rev.creator ?? rev.reviewer ?? ""}
                    {rev.rating && tab === "discord" && (
                      <span className="ml-2 text-yellow-400">{"★".repeat(rev.rating)}</span>
                    )}
                  </div>
                </div>
                <div className="flex items-center gap-1.5 shrink-0">
                  <span className="text-xs px-2 py-0.5 rounded-full" style={{ background: rev.visible ? "rgba(16,185,129,0.12)" : "rgba(255,255,255,0.06)", color: rev.visible ? "#34d399" : "rgba(255,255,255,0.3)", border: `1px solid ${rev.visible ? "rgba(16,185,129,0.2)" : "rgba(255,255,255,0.08)"}` }}>
                    {rev.visible ? "Live" : "Hidden"}
                  </span>
                  <button onClick={() => toggleVisible(rev)} title="Toggle visibility" className="p-1.5 rounded-lg text-white/30 hover:text-white hover:bg-white/8 transition-colors">
                    {rev.visible ? <Eye size={13} /> : <EyeOff size={13} />}
                  </button>
                  <button onClick={() => openEdit(rev)} className="p-1.5 rounded-lg text-white/30 hover:text-blue-400 hover:bg-blue-500/10 transition-colors">
                    <Pencil size={13} />
                  </button>
                  <button onClick={() => setConfirmId(rev.id)} className="p-1.5 rounded-lg text-white/30 hover:text-red-400 hover:bg-red-500/10 transition-colors">
                    <Trash2 size={13} />
                  </button>
                </div>
              </motion.div>
            ))}
          </div>
        )}
      </Card>
    </div>
  );
}

import { useState, useEffect, useCallback } from "react";
import { AnimatePresence, motion } from "framer-motion";
import { Plus, Pencil, Trash2, Eye, EyeOff, RefreshCw, Copy, Star } from "lucide-react";
import { Toast, ConfirmDialog, GlassInput, GlassTextarea, GlassSelect, Card, SectionHeader, SaveButton, Modal, Badge } from "./shared";

interface Plan {
  id: number; service: string; title: string; price: number; currency: string;
  billingPeriod: string; cpu: string | null; ram: string | null; storage: string | null;
  bandwidth: string | null; location: string | null; buttonText: string | null;
  buttonUrl: string | null; features: string[]; badge: string | null;
  popular: number; bgColor: string | null; status: string; sortOrder: number;
}

const SERVICES = [
  { value: "minecraft", label: "Minecraft Hosting" },
  { value: "vps",       label: "VPS Hosting" },
  { value: "rdp",       label: "RDP Hosting" },
  { value: "dedicated", label: "Dedicated Servers" },
  { value: "discord-bot", label: "Discord Bot Hosting" },
  { value: "web",       label: "Web Hosting" },
];

const CURRENCIES = ["INR", "USD", "EUR", "GBP"].map(c => ({ value: c, label: c }));
const PERIODS    = ["monthly","quarterly","yearly","lifetime"].map(p => ({ value: p, label: p.charAt(0).toUpperCase() + p.slice(1) }));
const STATUSES   = [{ value: "active", label: "Active" }, { value: "hidden", label: "Hidden" }, { value: "archived", label: "Archived" }];

const EMPTY: Partial<Plan> & { featuresText: string } = {
  service: "minecraft", title: "", price: 0, currency: "INR", billingPeriod: "monthly",
  cpu: "", ram: "", storage: "", bandwidth: "", location: "",
  buttonText: "Order Now", buttonUrl: "", badge: "", bgColor: "",
  popular: 0, status: "active", sortOrder: 0, featuresText: "",
};

export default function PlansManager({ token }: { token: string }) {
  const [serviceFilter, setServiceFilter] = useState("all");
  const [plans, setPlans] = useState<Plan[]>([]);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [modal, setModal] = useState<null | "add" | number>(null);
  const [form, setForm] = useState({ ...EMPTY });
  const [confirmId, setConfirmId] = useState<number | null>(null);
  const [toast, setToast] = useState<{ msg: string; type: "success" | "error" } | null>(null);

  const load = useCallback(async () => {
    setLoading(true);
    try {
      const r = await fetch("/api/plans/admin", { headers: { Authorization: `Bearer ${token}` } });
      const d = await r.json() as { plans?: Plan[] };
      setPlans(d.plans ?? []);
    } finally { setLoading(false); }
  }, [token]);

  useEffect(() => { load(); }, [load]);

  const filtered = serviceFilter === "all" ? plans : plans.filter(p => p.service === serviceFilter);

  const openAdd = () => {
    setForm({ ...EMPTY, service: serviceFilter === "all" ? "minecraft" : serviceFilter });
    setModal("add");
  };

  const openEdit = (p: Plan) => {
    setForm({ ...p, featuresText: (p.features ?? []).join("\n") });
    setModal(p.id);
  };

  const duplicate = async (p: Plan) => {
    const payload = { ...p, title: p.title + " (Copy)", id: undefined, features: p.features };
    const r = await fetch("/api/plans", { method: "POST", headers: { Authorization: `Bearer ${token}`, "Content-Type": "application/json" }, body: JSON.stringify(payload) });
    if (r.ok) { setToast({ msg: "Plan duplicated.", type: "success" }); load(); }
    else setToast({ msg: "Duplicate failed.", type: "error" });
  };

  const set = (k: string, v: unknown) => setForm(f => ({ ...f, [k]: v }));

  const save = async () => {
    if (!form.title) return setToast({ msg: "Title is required.", type: "error" });
    setSaving(true);
    try {
      const features = (form.featuresText || "").split("\n").map(s => s.trim()).filter(Boolean);
      const payload = { ...form, features, price: Number(form.price) || 0, sortOrder: Number(form.sortOrder) || 0, popular: form.popular ? 1 : 0 };
      delete (payload as Record<string, unknown>).featuresText;
      const isEdit = typeof modal === "number";
      const r = await fetch(isEdit ? `/api/plans/${modal}` : "/api/plans", {
        method: isEdit ? "PATCH" : "POST",
        headers: { Authorization: `Bearer ${token}`, "Content-Type": "application/json" },
        body: JSON.stringify(payload),
      });
      if (r.ok) {
        setToast({ msg: isEdit ? "Plan updated." : "Plan created.", type: "success" });
        setModal(null); load();
      } else {
        const e = await r.json() as { error?: string };
        setToast({ msg: e.error ?? "Save failed.", type: "error" });
      }
    } finally { setSaving(false); }
  };

  const deletePlan = async (id: number) => {
    const r = await fetch(`/api/plans/${id}`, { method: "DELETE", headers: { Authorization: `Bearer ${token}` } });
    if (r.ok) { setToast({ msg: "Plan deleted.", type: "success" }); setPlans(ps => ps.filter(p => p.id !== id)); }
    else setToast({ msg: "Delete failed.", type: "error" });
    setConfirmId(null);
  };

  const toggleStatus = async (p: Plan) => {
    const status = p.status === "active" ? "hidden" : "active";
    await fetch(`/api/plans/${p.id}`, { method: "PATCH", headers: { Authorization: `Bearer ${token}`, "Content-Type": "application/json" }, body: JSON.stringify({ status }) });
    setPlans(ps => ps.map(x => x.id === p.id ? { ...x, status } : x));
  };

  return (
    <div>
      <SectionHeader title="Plans Manager" subtitle="Create and manage hosting plans — they appear on your hosting pages" />
      {toast && <AnimatePresence><Toast msg={toast.msg} type={toast.type} onClose={() => setToast(null)} /></AnimatePresence>}
      {confirmId !== null && <ConfirmDialog msg="Permanently delete this plan?" onConfirm={() => deletePlan(confirmId)} onCancel={() => setConfirmId(null)} />}

      {modal !== null && (
        <AnimatePresence>
          <Modal title={typeof modal === "number" ? "Edit Plan" : "Create Plan"} onClose={() => setModal(null)}>
            <div className="space-y-4 max-h-[70vh] overflow-y-auto pr-1">
              <div className="grid grid-cols-2 gap-4">
                <GlassSelect label="Service" value={form.service as string} onChange={v => set("service", v)} options={SERVICES} />
                <GlassInput label="Plan Title" value={form.title as string} onChange={v => set("title", v)} placeholder="Starter Plan" />
              </div>
              <div className="grid grid-cols-3 gap-3">
                <GlassInput label="Price" value={String(form.price ?? "")} onChange={v => set("price", v)} type="number" placeholder="299" />
                <GlassSelect label="Currency" value={form.currency as string} onChange={v => set("currency", v)} options={CURRENCIES} />
                <GlassSelect label="Billing" value={form.billingPeriod as string} onChange={v => set("billingPeriod", v)} options={PERIODS} />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <GlassInput label="CPU" value={form.cpu as string} onChange={v => set("cpu", v)} placeholder="2 vCPU" />
                <GlassInput label="RAM" value={form.ram as string} onChange={v => set("ram", v)} placeholder="4GB" />
                <GlassInput label="Storage" value={form.storage as string} onChange={v => set("storage", v)} placeholder="50GB NVMe" />
                <GlassInput label="Bandwidth" value={form.bandwidth as string} onChange={v => set("bandwidth", v)} placeholder="Unlimited" />
              </div>
              <GlassInput label="Location" value={form.location as string} onChange={v => set("location", v)} placeholder="India, Singapore, Dubai" />
              <GlassTextarea label="Features (one per line)" value={form.featuresText as string} onChange={v => set("featuresText", v)} rows={4} placeholder={"DDoS Protection\nInstant Setup\n24/7 Support"} />
              <div className="grid grid-cols-2 gap-4">
                <GlassInput label="Button Text" value={form.buttonText as string} onChange={v => set("buttonText", v)} placeholder="Order Now" />
                <GlassInput label="Button URL" value={form.buttonUrl as string} onChange={v => set("buttonUrl", v)} placeholder="https://..." />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <GlassInput label="Badge (e.g. HOT)" value={form.badge as string} onChange={v => set("badge", v)} placeholder="HOT" />
                <GlassSelect label="Status" value={form.status as string} onChange={v => set("status", v)} options={STATUSES} />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <GlassInput label="Sort Order" value={String(form.sortOrder ?? 0)} onChange={v => set("sortOrder", v)} type="number" />
                <div>
                  <label className="block text-xs font-semibold text-white/40 uppercase tracking-widest mb-1.5">Popular</label>
                  <button onClick={() => set("popular", form.popular ? 0 : 1)}
                    className="w-full flex items-center gap-2 px-4 py-2.5 rounded-xl text-sm font-medium transition-all"
                    style={{ background: form.popular ? "rgba(250,204,21,0.12)" : "rgba(255,255,255,0.04)", border: `1px solid ${form.popular ? "rgba(250,204,21,0.3)" : "rgba(255,255,255,0.08)"}`, color: form.popular ? "#fbbf24" : "rgba(255,255,255,0.4)" }}>
                    <Star size={14} fill={form.popular ? "currentColor" : "none"} />
                    {form.popular ? "Popular" : "Not Popular"}
                  </button>
                </div>
              </div>
              <div className="pt-2">
                <SaveButton loading={saving} onClick={save} label={typeof modal === "number" ? "Update Plan" : "Create Plan"} />
              </div>
            </div>
          </Modal>
        </AnimatePresence>
      )}

      {/* Filter + Add */}
      <div className="flex gap-2 mb-6 flex-wrap">
        <button onClick={() => setServiceFilter("all")}
          className="px-3 py-1.5 rounded-lg text-xs font-medium transition-all"
          style={{ background: serviceFilter === "all" ? "rgba(99,102,241,0.2)" : "rgba(255,255,255,0.04)", border: `1px solid ${serviceFilter === "all" ? "rgba(99,102,241,0.4)" : "rgba(255,255,255,0.08)"}`, color: serviceFilter === "all" ? "#a5b4fc" : "rgba(255,255,255,0.4)" }}>
          All ({plans.length})
        </button>
        {SERVICES.map(s => (
          <button key={s.value} onClick={() => setServiceFilter(s.value)}
            className="px-3 py-1.5 rounded-lg text-xs font-medium transition-all"
            style={{ background: serviceFilter === s.value ? "rgba(99,102,241,0.2)" : "rgba(255,255,255,0.04)", border: `1px solid ${serviceFilter === s.value ? "rgba(99,102,241,0.4)" : "rgba(255,255,255,0.08)"}`, color: serviceFilter === s.value ? "#a5b4fc" : "rgba(255,255,255,0.4)" }}>
            {s.label} ({plans.filter(p => p.service === s.value).length})
          </button>
        ))}
        <button onClick={load} className="ml-auto flex items-center gap-1.5 px-3 py-2 rounded-xl text-xs text-white/40 hover:text-white border border-white/8 transition-colors">
          <RefreshCw size={12} /> Refresh
        </button>
        <button onClick={openAdd} className="flex items-center gap-2 px-4 py-2 rounded-xl text-sm font-semibold text-white"
          style={{ background: "linear-gradient(135deg,#2563eb,#7c3aed)", boxShadow: "0 0 16px rgba(99,102,241,0.3)" }}>
          <Plus size={14} /> Create Plan
        </button>
      </div>

      <Card>
        {loading ? (
          <div className="text-center py-12 text-white/30 text-sm">Loading plans...</div>
        ) : filtered.length === 0 ? (
          <div className="text-center py-12 text-white/25 text-sm">No plans found. Click Create Plan to add one.</div>
        ) : (
          <div className="overflow-x-auto">
            <table className="w-full text-sm">
              <thead>
                <tr className="border-b border-white/8">
                  {["Plan","Service","Price","Status","Popular",""].map(h => (
                    <th key={h} className="text-left py-3 px-2 text-xs font-semibold text-white/30 uppercase tracking-wide">{h}</th>
                  ))}
                </tr>
              </thead>
              <tbody>
                {filtered.map(p => (
                  <tr key={p.id} className="border-b border-white/5 last:border-0 hover:bg-white/3 transition-colors">
                    <td className="py-3 px-2">
                      <div className="text-white font-medium">{p.title}</div>
                      {p.badge && <Badge color="#f59e0b">{p.badge}</Badge>}
                    </td>
                    <td className="py-3 px-2 text-white/50 text-xs">{SERVICES.find(s => s.value === p.service)?.label}</td>
                    <td className="py-3 px-2 text-white/70">{p.currency} {p.price}/{p.billingPeriod}</td>
                    <td className="py-3 px-2">
                      <Badge color={p.status === "active" ? "#22c55e" : "#ef4444"}>{p.status}</Badge>
                    </td>
                    <td className="py-3 px-2">{p.popular ? <Star size={14} className="text-yellow-400" fill="currentColor" /> : <span className="text-white/20">—</span>}</td>
                    <td className="py-3 px-2 text-right">
                      <div className="flex items-center gap-1 justify-end">
                        <button onClick={() => toggleStatus(p)} title="Toggle" className="p-1.5 rounded-lg text-white/30 hover:text-white hover:bg-white/8 transition-colors">
                          {p.status === "active" ? <Eye size={13} /> : <EyeOff size={13} />}
                        </button>
                        <button onClick={() => duplicate(p)} title="Duplicate" className="p-1.5 rounded-lg text-white/30 hover:text-blue-400 hover:bg-blue-500/10 transition-colors">
                          <Copy size={13} />
                        </button>
                        <button onClick={() => openEdit(p)} className="p-1.5 rounded-lg text-white/30 hover:text-indigo-400 hover:bg-indigo-500/10 transition-colors">
                          <Pencil size={13} />
                        </button>
                        <button onClick={() => setConfirmId(p.id)} className="p-1.5 rounded-lg text-white/30 hover:text-red-400 hover:bg-red-500/10 transition-colors">
                          <Trash2 size={13} />
                        </button>
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </Card>
    </div>
  );
}

import { useState, useEffect, useCallback } from "react";
import { AnimatePresence, motion } from "framer-motion";
import { Pencil, Eye, EyeOff, RefreshCw, Plus, Trash2 } from "lucide-react";
import { Toast, ConfirmDialog, GlassInput, GlassTextarea, Card, SectionHeader, SaveButton, Modal, Badge } from "./shared";

interface Service {
  id: number; slug: string; name: string; icon: string;
  description: string | null; features: string[]; pricingLink: string | null;
  orderUrl: string | null; imageUrl: string | null; visible: number; sortOrder: number;
}

const EMPTY: Partial<Service> & { featuresText: string } = {
  slug: "", name: "", icon: "🖥️", description: "", pricingLink: "", orderUrl: "", imageUrl: "", visible: 1, sortOrder: 0, featuresText: "",
};

export default function ServicesManager({ token }: { token: string }) {
  const [services, setServices] = useState<Service[]>([]);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [modal, setModal] = useState<null | "add" | number>(null);
  const [form, setForm] = useState({ ...EMPTY });
  const [confirmId, setConfirmId] = useState<number | null>(null);
  const [toast, setToast] = useState<{ msg: string; type: "success" | "error" } | null>(null);

  const load = useCallback(async () => {
    setLoading(true);
    try {
      const r = await fetch("/api/services-config/admin", { headers: { Authorization: `Bearer ${token}` } });
      const d = await r.json() as { services?: Service[] };
      setServices(d.services ?? []);
    } finally { setLoading(false); }
  }, [token]);

  useEffect(() => { load(); }, [load]);

  const set = (k: string, v: unknown) => setForm(f => ({ ...f, [k]: v }));

  const openEdit = (s: Service) => {
    setForm({ ...s, featuresText: (s.features ?? []).join("\n") });
    setModal(s.id);
  };

  const openAdd = () => { setForm({ ...EMPTY }); setModal("add"); };

  const save = async () => {
    if (!form.name) return setToast({ msg: "Name is required.", type: "error" });
    setSaving(true);
    try {
      const features = (form.featuresText || "").split("\n").map(s => s.trim()).filter(Boolean);
      const payload = { ...form, features };
      delete (payload as Record<string, unknown>).featuresText;
      const isEdit = typeof modal === "number";
      const r = await fetch(isEdit ? `/api/services-config/${modal}` : "/api/services-config", {
        method: isEdit ? "PATCH" : "POST",
        headers: { Authorization: `Bearer ${token}`, "Content-Type": "application/json" },
        body: JSON.stringify(payload),
      });
      if (r.ok) {
        setToast({ msg: isEdit ? "Service updated." : "Service created.", type: "success" });
        setModal(null); load();
      } else {
        const e = await r.json() as { error?: string };
        setToast({ msg: e.error ?? "Save failed.", type: "error" });
      }
    } finally { setSaving(false); }
  };

  const toggleVisible = async (s: Service) => {
    const visible = s.visible ? 0 : 1;
    await fetch(`/api/services-config/${s.id}`, { method: "PATCH", headers: { Authorization: `Bearer ${token}`, "Content-Type": "application/json" }, body: JSON.stringify({ visible }) });
    setServices(ss => ss.map(x => x.id === s.id ? { ...x, visible } : x));
  };

  const deleteService = async (id: number) => {
    const r = await fetch(`/api/services-config/${id}`, { method: "DELETE", headers: { Authorization: `Bearer ${token}` } });
    if (r.ok) { setToast({ msg: "Service deleted.", type: "success" }); setServices(ss => ss.filter(s => s.id !== id)); }
    else setToast({ msg: "Delete failed.", type: "error" });
    setConfirmId(null);
  };

  return (
    <div>
      <SectionHeader title="Services Manager" subtitle="Manage the hosting services shown on your website" />
      {toast && <AnimatePresence><Toast msg={toast.msg} type={toast.type} onClose={() => setToast(null)} /></AnimatePresence>}
      {confirmId !== null && <ConfirmDialog msg="Delete this service card?" onConfirm={() => deleteService(confirmId)} onCancel={() => setConfirmId(null)} />}

      {modal !== null && (
        <AnimatePresence>
          <Modal title={typeof modal === "number" ? "Edit Service" : "Add Service"} onClose={() => setModal(null)}>
            <div className="space-y-4">
              <div className="grid grid-cols-3 gap-3">
                <GlassInput label="Icon (emoji)" value={form.icon as string} onChange={v => set("icon", v)} placeholder="⛏️" />
                <div className="col-span-2">
                  <GlassInput label="Service Name" value={form.name as string} onChange={v => set("name", v)} placeholder="Minecraft Hosting" />
                </div>
              </div>
              {typeof modal === "add" && (
                <GlassInput label="Slug (unique ID)" value={form.slug as string} onChange={v => set("slug", v)} placeholder="minecraft" />
              )}
              <GlassTextarea label="Description" value={form.description as string} onChange={v => set("description", v)} rows={2} placeholder="High-performance hosting with DDoS protection..." />
              <GlassTextarea label="Features (one per line)" value={form.featuresText as string} onChange={v => set("featuresText", v)} rows={4} placeholder={"DDoS Protection\nInstant Setup\n24/7 Support"} />
              <div className="grid grid-cols-2 gap-4">
                <GlassInput label="Pricing Page URL" value={form.pricingLink as string} onChange={v => set("pricingLink", v)} placeholder="/minecraft-hosting" />
                <GlassInput label="Order Button URL" value={form.orderUrl as string} onChange={v => set("orderUrl", v)} placeholder="https://discord.gg/..." />
              </div>
              <GlassInput label="Image URL (optional)" value={form.imageUrl as string} onChange={v => set("imageUrl", v)} placeholder="https://..." />
              <div className="grid grid-cols-2 gap-4">
                <GlassInput label="Sort Order" value={String(form.sortOrder ?? 0)} onChange={v => set("sortOrder", Number(v))} type="number" />
                <div>
                  <label className="block text-xs font-semibold text-white/40 uppercase tracking-widest mb-1.5">Visibility</label>
                  <button onClick={() => set("visible", form.visible ? 0 : 1)}
                    className="w-full flex items-center gap-2 px-4 py-2.5 rounded-xl text-sm font-medium transition-all"
                    style={{ background: form.visible ? "rgba(16,185,129,0.12)" : "rgba(255,255,255,0.04)", border: `1px solid ${form.visible ? "rgba(16,185,129,0.3)" : "rgba(255,255,255,0.08)"}`, color: form.visible ? "#34d399" : "rgba(255,255,255,0.4)" }}>
                    {form.visible ? <Eye size={14} /> : <EyeOff size={14} />}
                    {form.visible ? "Visible" : "Hidden"}
                  </button>
                </div>
              </div>
              <div className="pt-2">
                <SaveButton loading={saving} onClick={save} label={typeof modal === "number" ? "Update Service" : "Create Service"} />
              </div>
            </div>
          </Modal>
        </AnimatePresence>
      )}

      <div className="flex justify-end gap-2 mb-6">
        <button onClick={load} className="flex items-center gap-1.5 px-3 py-2 rounded-xl text-xs text-white/40 hover:text-white border border-white/8 transition-colors">
          <RefreshCw size={12} /> Refresh
        </button>
        <button onClick={openAdd} className="flex items-center gap-2 px-4 py-2 rounded-xl text-sm font-semibold text-white"
          style={{ background: "linear-gradient(135deg,#2563eb,#7c3aed)", boxShadow: "0 0 16px rgba(99,102,241,0.3)" }}>
          <Plus size={14} /> Add Service
        </button>
      </div>

      {loading ? (
        <div className="text-center py-16 text-white/30 text-sm">Loading services...</div>
      ) : (
        <div className="grid gap-4">
          {services.map(s => (
            <motion.div key={s.id} initial={{ opacity: 0 }} animate={{ opacity: 1 }}>
              <Card>
                <div className="flex items-start gap-4">
                  <div className="text-3xl shrink-0">{s.icon}</div>
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-2 mb-1">
                      <span className="text-white font-semibold">{s.name}</span>
                      <Badge color={s.visible ? "#22c55e" : "#6b7280"}>{s.visible ? "Visible" : "Hidden"}</Badge>
                    </div>
                    <p className="text-white/45 text-sm mb-2">{s.description}</p>
                    <div className="flex flex-wrap gap-1.5">
                      {(s.features ?? []).map((f, i) => (
                        <span key={i} className="text-xs px-2 py-0.5 rounded-full text-white/50" style={{ background: "rgba(255,255,255,0.06)", border: "1px solid rgba(255,255,255,0.08)" }}>{f}</span>
                      ))}
                    </div>
                  </div>
                  <div className="flex items-center gap-1.5 shrink-0">
                    <button onClick={() => toggleVisible(s)} className="p-2 rounded-lg text-white/30 hover:text-white hover:bg-white/8 transition-colors">
                      {s.visible ? <Eye size={14} /> : <EyeOff size={14} />}
                    </button>
                    <button onClick={() => openEdit(s)} className="p-2 rounded-lg text-white/30 hover:text-indigo-400 hover:bg-indigo-500/10 transition-colors">
                      <Pencil size={14} />
                    </button>
                    <button onClick={() => setConfirmId(s.id)} className="p-2 rounded-lg text-white/30 hover:text-red-400 hover:bg-red-500/10 transition-colors">
                      <Trash2 size={14} />
                    </button>
                  </div>
                </div>
              </Card>
            </motion.div>
          ))}
        </div>
      )}
    </div>
  );
}

import { useState, useEffect, useCallback } from "react";
import { AnimatePresence, motion } from "framer-motion";
import { Plus, Pencil, Trash2, Eye, EyeOff, RefreshCw, BookOpen } from "lucide-react";
import { Toast, ConfirmDialog, GlassInput, GlassTextarea, GlassSelect, Card, SectionHeader, SaveButton, Modal, Badge } from "./shared";

interface Doc {
  id: number; category: string; title: string; slug: string | null;
  content: string; published: number; sortOrder: number;
  createdAt: string; updatedAt: string;
}

const CATEGORIES = [
  { value: "general",    label: "General" },
  { value: "getting-started", label: "Getting Started" },
  { value: "billing",    label: "Billing" },
  { value: "minecraft",  label: "Minecraft" },
  { value: "vps",        label: "VPS" },
  { value: "rdp",        label: "RDP" },
  { value: "faq",        label: "FAQ" },
  { value: "other",      label: "Other" },
];

const EMPTY = { category: "general", title: "", slug: "", content: "", published: 0, sortOrder: 0 };

export default function DocsManager({ token }: { token: string }) {
  const [docs, setDocs] = useState<Doc[]>([]);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [modal, setModal] = useState<null | "add" | number>(null);
  const [form, setForm] = useState({ ...EMPTY });
  const [search, setSearch] = useState("");
  const [catFilter, setCatFilter] = useState("all");
  const [confirmId, setConfirmId] = useState<number | null>(null);
  const [toast, setToast] = useState<{ msg: string; type: "success" | "error" } | null>(null);

  const load = useCallback(async () => {
    setLoading(true);
    try {
      const r = await fetch("/api/docs/admin", { headers: { Authorization: `Bearer ${token}` } });
      const d = await r.json() as { docs?: Doc[] };
      setDocs(d.docs ?? []);
    } finally { setLoading(false); }
  }, [token]);

  useEffect(() => { load(); }, [load]);

  const set = (k: string, v: unknown) => setForm(f => ({ ...f, [k]: v }));

  const openAdd = () => { setForm({ ...EMPTY }); setModal("add"); };
  const openEdit = (d: Doc) => { setForm({ category: d.category, title: d.title, slug: d.slug ?? "", content: d.content, published: d.published, sortOrder: d.sortOrder }); setModal(d.id); };

  const save = async () => {
    if (!form.title) return setToast({ msg: "Title is required.", type: "error" });
    if (!form.content) return setToast({ msg: "Content is required.", type: "error" });
    setSaving(true);
    try {
      const isEdit = typeof modal === "number";
      const r = await fetch(isEdit ? `/api/docs/${modal}` : "/api/docs", {
        method: isEdit ? "PATCH" : "POST",
        headers: { Authorization: `Bearer ${token}`, "Content-Type": "application/json" },
        body: JSON.stringify({ ...form, published: form.published ? 1 : 0, sortOrder: Number(form.sortOrder) || 0 }),
      });
      if (r.ok) {
        setToast({ msg: isEdit ? "Doc updated." : "Doc created.", type: "success" });
        setModal(null); load();
      } else {
        const e = await r.json() as { error?: string };
        setToast({ msg: e.error ?? "Save failed.", type: "error" });
      }
    } finally { setSaving(false); }
  };

  const togglePublished = async (doc: Doc) => {
    const published = doc.published ? 0 : 1;
    await fetch(`/api/docs/${doc.id}`, { method: "PATCH", headers: { Authorization: `Bearer ${token}`, "Content-Type": "application/json" }, body: JSON.stringify({ published }) });
    setDocs(ds => ds.map(d => d.id === doc.id ? { ...d, published } : d));
  };

  const deleteDoc = async (id: number) => {
    const r = await fetch(`/api/docs/${id}`, { method: "DELETE", headers: { Authorization: `Bearer ${token}` } });
    if (r.ok) { setToast({ msg: "Doc deleted.", type: "success" }); setDocs(ds => ds.filter(d => d.id !== id)); }
    else setToast({ msg: "Delete failed.", type: "error" });
    setConfirmId(null);
  };

  const filtered = docs
    .filter(d => catFilter === "all" || d.category === catFilter)
    .filter(d => !search || d.title.toLowerCase().includes(search.toLowerCase()));

  return (
    <div>
      <SectionHeader title="Docs Manager" subtitle="Create and publish documentation articles" />
      {toast && <AnimatePresence><Toast msg={toast.msg} type={toast.type} onClose={() => setToast(null)} /></AnimatePresence>}
      {confirmId !== null && <ConfirmDialog msg="Permanently delete this document?" onConfirm={() => deleteDoc(confirmId)} onCancel={() => setConfirmId(null)} />}

      {modal !== null && (
        <AnimatePresence>
          <Modal title={typeof modal === "number" ? "Edit Document" : "New Document"} onClose={() => setModal(null)}>
            <div className="space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <GlassSelect label="Category" value={form.category} onChange={v => set("category", v)} options={CATEGORIES} />
                <GlassInput label="Sort Order" value={String(form.sortOrder)} onChange={v => set("sortOrder", v)} type="number" placeholder="0" />
              </div>
              <GlassInput label="Title" value={form.title} onChange={v => set("title", v)} placeholder="How to connect to your server" />
              <GlassInput label="Slug (optional)" value={form.slug} onChange={v => set("slug", v)} placeholder="auto-generated-from-title" />
              <GlassTextarea label="Content (Markdown supported)" value={form.content} onChange={v => set("content", v)} rows={10} placeholder={"# Getting Started\n\nWelcome to BruteScale documentation...\n\n## Step 1\n\nConnect to your server using..."} />
