    28→function useHashNav() {
    29→  const [location, navigate] = useLocation();
    30→  return (href: string) => {
    31→    if (!href.startsWith("#")) { navigate(href); return; }
    32→    const section = href.slice(1);
    33→    if (location === "/") {
    34→      document.getElementById(section)?.scrollIntoView({ behavior: "smooth" });
    35→    } else {
    36→      sessionStorage.setItem("bs_scroll_to", section);
    37→      navigate("/");
    38→    }
    39→  };
    40→}
